if ( ! function_exists( 'mike_social_icon_name' ) ) :
	/**
	 * Resolve a URL → a brand icon name. Matches the longest domain fragment so
	 * specific hosts win (music.apple.com → applemusic, not a generic apple).
	 * mailto:/tel: are matched on the scheme. Anything unrecognised → 'website'
	 * (the generic globe) so an unknown link still shows a sensible icon rather
	 * than nothing — this is the trust boundary for an editor-entered URL.
	 *
	 * @param string $url
	 * @return string Icon name guaranteed to exist in mike_icon_map().
	 */
	function mike_social_icon_name( $url ) {
		$url = strtolower( trim( (string) $url ) );
		if ( '' === $url ) {
			return 'website';
		}
		$map = mike_social_domain_map();

		// Scheme matches first (mailto:, tel:).
		foreach ( array( 'mailto:', 'tel:' ) as $scheme ) {
			if ( 0 === strpos( $url, $scheme ) ) {
				return $map[ $scheme ];
			}
		}

		// A bare email typed without the scheme: WP may store it as-is or prepend
		// http:// (→ "http://hello@domain.com"). Either way an '@' before any '/'
		// path means "this is an email" → email icon. Catches the common case
		// where the editor pastes hello@domain.com instead of mailto:hello@….
		$scheme_stripped = preg_replace( '#^https?://#', '', $url );
		if ( false !== strpos( $scheme_stripped, '@' ) && false === strpos( explode( '/', $scheme_stripped )[0], ' ' ) ) {
			$before_path = explode( '/', $scheme_stripped )[0];
			if ( false !== strpos( $before_path, '@' ) ) {
				return 'email';
			}
		}

		// Strip scheme + leading www. then match the host portion, longest key
		// first so 'music.apple.com' beats a hypothetical 'apple'.
		$host = $scheme_stripped;
		$host = preg_replace( '#^www\.#', '', $host );

		$keys = array_keys( $map );
		usort( $keys, function ( $a, $b ) {
			return strlen( $b ) - strlen( $a );
		} );
		foreach ( $keys as $needle ) {
			if ( 'mailto:' === $needle || 'tel:' === $needle ) {
				continue;
			}
			if ( false !== strpos( $host, $needle ) ) {
				return $map[ $needle ];
			}
		}
		return 'website';
	}
endif;

if ( ! function_exists( 'mike_social_icon' ) ) :
	/**
	 * Echo the brand icon for a URL (domain → icon). Thin wrapper over
	 * mike_social_icon_name() + mike_icon() so callers (the social menu walker /
	 * render) say what they mean.
	 *
	 * @param string $url
	 * @param array  $attrs Passed through to mike_icon() (class, size, label).
	 */
	function mike_social_icon( $url, $attrs = array() ) {
		mike_icon( mike_social_icon_name( $url ), $attrs );
	}
endif;
